import { Component, OnInit } from '@angular/core';
import { Animal } from '../../models/animal.model';

@Component({
  selector: 'app-adopcion',
  templateUrl: './adopcion.component.html',
  styleUrls: ['./adopcion.component.css']
})
export class AdopcionComponent implements OnInit {

  // La lista debe seguir estrictamente el contrato del modelo Animal 
  listaAnimales: Animal[] = [
    {
      nombre: 'Rocky',
      especie: 'Perro',
      edad: 3, // Sin comillas para que sea tipo number
      imagen: 'assets/perro.jpg',
      descripcion: 'Un perro muy juguetón y fiel.'
    },
    {
      nombre: 'Luna',
      especie: 'Gato',
      edad: 2, // Sin comillas para que sea tipo number
      imagen: 'assets/gato.jpg',
      descripcion: 'Tranquila y le encanta dormir al sol.'
    }
  ];

  constructor() { }

  ngOnInit(): void {
    // Aquí podrías cargar datos de una API o JSON externo más adelante 
  }
}
